20	// FP32
21	// Warp Reduce Sum
22	template <const int kWarpSize = WARP_SIZE>
23	__device__ __forceinline__ float warp_reduce_sum_f32(float val) {
24	#pragma unroll
25	  for (int mask = kWarpSize >> 1; mask >= 1; mask >>= 1) {
26	    val += __shfl_xor_sync(0xffffffff, val, mask);
27	  }
28	  return val;
29	}
30	
31	// Dot Product
32	// grid(N/256), block(256)
33	// a: Nx1, b: Nx1, y=sum(elementwise_mul(a,b))
34	template <const int NUM_THREADS = 256>
35	__global__ void dot_prod_f32_f32_kernel(float *a, float *b, float *y, int N) {
36	  int tid = threadIdx.x;
37	  int idx = blockIdx.x * NUM_THREADS + tid;
38	  constexpr int NUM_WARPS = (NUM_THREADS + WARP_SIZE - 1) / WARP_SIZE;
39	  __shared__ float reduce_smem[NUM_WARPS];
40	
41	  // keep the data in register is enough for warp operaion.
42	  float prod = (idx < N) ? a[idx] * b[idx] : 0.0f;
43	  int warp = tid / WARP_SIZE;
44	  int lane = tid % WARP_SIZE;
45	  // perform warp sync reduce.
46	  prod = warp_reduce_sum_f32<WARP_SIZE>(prod);
47	  // warp leaders store the data to shared memory.
48	  if (lane == 0)
49	    reduce_smem[warp] = prod;
